     2→  import { onMount } from 'svelte';
     3→  import { Card, Button } from '@torca/ui';
     4→  
     5→  export let error: Error | null = null;
     6→  export let resetError: () => void = () => {};
     7→  
     8→  // Capture errors during component lifecycle
     9→  onMount(() => {
    10→    const handleError = (event: ErrorEvent) => {
    11→      error = new Error(event.message);
    12→      event.preventDefault();
    13→    };
    14→    
    15→    const handleUnhandledRejection = (event: PromiseRejectionEvent) => {
    16→      error = new Error(event.reason?.message || 'Unhandled promise rejection');
    17→      event.preventDefault();
    18→    };
    19→    
    20→    window.addEventListener('error', handleError);
    21→    window.addEventListener('unhandledrejection', handleUnhandledRejection);
    22→    
    23→    return () => {
    24→      window.removeEventListener('error', handleError);
    25→      window.removeEventListener('unhandledrejection', handleUnhandledRejection);
    26→    };
    27→  });
    28→  
    29→  function handleReset() {
    30→    error = null;
    31→    resetError();
    32→    window.location.reload();
    33→  }
