import { getContext, setContext } from 'svelte';
import type { ServiceContainer } from '@torca/services';

const SERVICES_KEY = Symbol('services');

/**
 * Set services in Svelte context
 */
export function setServices(services: ServiceContainer): void {
  setContext(SERVICES_KEY, services);
}

/**
 * Get services from Svelte context
 */
export function getServices(): ServiceContainer {
  return getContext<ServiceContainer>(SERVICES_KEY);
}

/**
 * Get session service from context
 */
export function useSessionService() {
  const services = getServices();
  if (!services) {
    throw new Error('Services not found in context. Make sure to call setServices in a parent component.');
  }
  return services.session;
}

/**
 * Get participant service from context
 */
export function useParticipantService() {
  const services = getServices();
  if (!services) {
    throw new Error('Services not found in context. Make sure to call setServices in a parent component.');
  }
  return services.participant;
}

/**
 * Get template service from context
 */
export function useTemplateService() {
  const services = getServices();
  if (!services) {
    throw new Error('Services not found in context. Make sure to call setServices in a parent component.');
  }
  return services.template;
}

