     8→  // Props
     9→  export let fallback: any = null;
    10→  export let onError: ((error: Error, errorInfo: any) => void) | null = null;
    11→  export let resetKeys: any[] = [];
    12→  export let resetOnPropsChange: boolean = true;
    13→  export let isolate: boolean = true;
    14→  export let level: 'page' | 'section' | 'component' = 'component';
    15→  
    16→  // State
    17→  let hasError = false;
    18→  let error: Error | null = null;
    19→  let errorInfo: any = null;
    20→  let retryCount = 0;
    21→  const MAX_RETRIES = 3;
    22→  
    23→  const dispatch = createEventDispatcher();
    24→  
    25→  // Error handling
    26→  function handleError(err: Error, info?: any) {
    27→    hasError = true;
    28→    error = err;
    29→    errorInfo = info || {
    30→      componentStack: '',
    31→      timestamp: new Date().toISOString()
    32→    };
    33→    
    34→    // Log error
    35→    console.error('Error Boundary caught:', err, info);
    36→    
    37→    // Call error handler
    38→    onError?.(err, errorInfo);
    39→    
    40→    // Dispatch event
    41→    dispatch('error', { error: err, errorInfo, retryCount });
    42→  }
    43→  
    44→  // Reset error state
    45→  export function resetError() {
    46→    hasError = false;
    47→    error = null;
    48→    errorInfo = null;
    49→    retryCount = 0;
    50→    dispatch('reset');
    51→  }
    52→  
    53→  // Retry with count
    54→  function retry() {
    55→    if (retryCount < MAX_RETRIES) {
    56→      retryCount++;
    57→      resetError();
    58→    }
    59→  }
    60→  
    61→  // Watch for prop changes to reset
    62→  $: if (resetOnPropsChange && resetKeys.length > 0) {
    63→    // Reset when specified props change
    64→    resetKeys.forEach(() => {
    65→      if (hasError) {
    66→        resetError();
    67→      }
    68→    });
    69→  }
    70→  
    71→  // Set up global error handler for this component tree
    72→  let originalHandler: any;
    73→  let errorHandler: any;
    74→  
    75→  onMount(() => {
    76→    if (isolate) {
    77→      // Store original handler
    78→      originalHandler = window.onerror;
    79→      
    80→      // Create scoped error handler
    81→      errorHandler = (message: string, source: string, lineno: number, colno: number, err: Error) => {
    82→        // Check if error originated from this component tree
    83→        const errorElement = document.querySelector('[data-error-boundary]');
    84→        if (errorElement && errorElement.contains(document.activeElement)) {
    85→          handleError(err || new Error(message), {
    86→            source,
    87→            lineno,
    88→            colno,
    89→            timestamp: new Date().toISOString()
    90→          });
    91→          return true; // Prevent default error handling
    92→        }
    93→        return false;
    94→      };
    95→      
    96→      window.onerror = errorHandler;
    97→    }
    98→  });
    99→  
   100→  onDestroy(() => {
   101→    if (isolate && originalHandler) {
   102→      window.onerror = originalHandler;
   103→    }
   104→  });
   105→  
   106→  // Catch promise rejections in component tree
   107→  function handlePromiseRejection(event: PromiseRejectionEvent) {
   108→    handleError(new Error(event.reason), {
   109→      type: 'unhandledRejection',
   110→      promise: event.promise,
   111→      reason: event.reason
   112→    });
   113→  }
