      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function jumpToTask(index: number): Promise<void> {
    const $tasks = get(tasks);
    const $session = get(session);

    if (!$session || index < 0 || index >= $tasks.length) return;

    try {
      setLoading(true);
      setError(null);

      // If session is draft, start it first
      if ($session.state === 'draft') {
        await start();
      }

      // Mark current task as skipped if in progress
      const currentResults = get(results);
      const currentIndex = get(currentTaskIndex);
      const currentResult = currentResults.find(r => r.task_index === currentIndex);

      if (currentResult?.state === 'in_progress') {
        await skipCurrentTask('Jumped to another task');
      }

      // Update session
      updateSession({
        current_task_index: index
      });

      activeView.set('execution');

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to jump to task');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function skipCurrentTask(reason?: string): Promise<void> {
    const $currentTask = get(currentTask);
    const $currentIndex = get(currentTaskIndex);
    const $tasks = get(tasks);

    if (!$currentTask) return;

    try {
      setLoading(true);
      setError(null);

      // Update current result
      results.update(allResults => {
        const currentResult = allResults.find(r => r.task_index === $currentIndex);
        if (currentResult) {
          currentResult.state = 'skipped';
          currentResult.end_time = new Date().toISOString();
          currentResult.duration_seconds = get(elapsedSeconds);
          currentResult.annotations = {
            ...currentResult.annotations,
            skipped_reason: reason || 'Manual skip'
          };
        }
        return allResults;
      });

      // Move to next task or complete
      const nextIndex = $currentIndex + 1;
      if (nextIndex < $tasks.length) {
        updateSession({ current_task_index: nextIndex });
      } else {
        await complete();
      }

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to skip task');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function submitTaskResult(result: Partial<TaskResult>): Promise<void> {
    const $currentIndex = get(currentTaskIndex);
    const $tasks = get(tasks);

    try {
      setLoading(true);
      setError(null);

      // Update results
      results.update(allResults => {
        const existing = allResults.find(r => r.task_index === $currentIndex);
        if (existing) {
          Object.assign(existing, result);
        }
        return allResults;
      });

      // Auto-advance if configured
      if (config.autoAdvance !== false) {
        const nextIndex = $currentIndex + 1;
        if (nextIndex < $tasks.length) {
          updateSession({ current_task_index: nextIndex });
        } else {
          await complete();
        }
      }

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to submit result');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function updatePresence(data: any): Promise<void> {
    // Implement realtime presence update
    // For now, this is a no-op
  }

  function destroy(): void {
    stopwatch?.destroy();
    // Clean up any subscriptions
  }

  return {
    // State
    session,
    tasks: { subscribe: tasks.subscribe },
    results,
    participant: { subscribe: participant.subscribe },

    // UI State
    currentTaskIndex,
    activeView,
    isLoading: { subscribe: isLoading.subscribe },
    error: { subscribe: error.subscribe },

    // Derived
    currentTask,
    progress,
    canStart,
    canPause,
    canResume,
    isComplete,

    // Actions
    initialize,
    start,
    pause,
    resume,
    complete,
    jumpToTask,
    skipCurrentTask,
    submitTaskResult,
    updatePresence,
    destroy
  };
}

