import { writable, derived, get } from 'svelte/store';
import type { 
  SessionStore, 
  Session, 
  Task, 
  TaskResult, 
  Participant,
  SessionConfig 
} from './types';
import { createStopwatch } from '@torca/shared';
import type { ISessionService } from '@torca/services';

/**
 * Create a session store for managing assessment session state
 */
export function createSessionStore(
  config: SessionConfig = {},
  sessionService?: ISessionService
): SessionStore {
  // Core state stores
  const session = writable<Session | null>(null);
  const tasks = writable<Task[]>([]);
  const results = writable<TaskResult[]>([]);
  const participant = writable<Participant | null>(null);

  // UI state stores
  const activeView = writable<'overview' | 'execution' | 'monitor'>('overview');
  const isLoading = writable(false);
  const error = writable<string | null>(null);

  // Timer management
  let stopwatch: ReturnType<typeof createStopwatch> | null = null;
  const elapsedSeconds = writable(0);

  // Derived stores
  const currentTaskIndex = derived(
    session,
    $session => $session?.current_task_index || 0
  );

  const currentTask = derived(
    [tasks, currentTaskIndex],
    ([$tasks, $index]) => $tasks[$index] || null
  );

  const progress = derived(
    [tasks, results],
    ([$tasks, $results]) => {
      if ($tasks.length === 0) return 0;
      const completed = $results.filter(r => r.state === 'completed').length;
      return (completed / $tasks.length) * 100;
    }
  );

  const canStart = derived(
    session,
    $session => $session?.state === 'draft' && get(tasks).length > 0
  );

  const canPause = derived(
    session,
    $session => $session?.state === 'active'
  );

  const canResume = derived(
    session,
    $session => $session?.state === 'paused'
  );

  const isComplete = derived(
    session,
    $session => $session?.state === 'completed'
  );

  // Helper functions
  const setLoading = (loading: boolean) => isLoading.set(loading);
  const setError = (err: string | null) => error.set(err);

  const updateSession = (updates: Partial<Session>) => {
    session.update(s => s ? { ...s, ...updates } : null);
  };

  // Action implementations
  async function initialize(sessionId: string): Promise<void> {
    try {
      setLoading(true);
      setError(null);

      if (sessionService) {
        // Use service abstraction
        const sessionData = await sessionService.getById(sessionId);
        if (!sessionData) {
          throw new Error('Session not found');
        }

        session.set(sessionData);
        tasks.set(sessionData.tasks);
        results.set(sessionData.results);
        participant.set(sessionData.participant || null);
      } else {
        // In SvelteKit, we need to get the data from the page store
        // For now, let's create mock data directly
        console.log('SessionStore: Loading mock session data for:', sessionId);

        // Import the mock creator
        const { createCompleteBatterySession } = await import('$lib/mocks/sessions');

        let mockSession;
        if (sessionId.includes('battery')) {
          mockSession = createCompleteBatterySession(sessionId, 'mock-user-id');
        } else {
          // Default session
          mockSession = {
            id: sessionId,
            participant_id: 'p1111111-1111-1111-1111-111111111111',
            clinician_id: 'mock-user-id',
            supervisor_id: null,
            template_id: 't1111111-1111-1111-1111-111111111111',
            state: 'draft' as const,
            name: 'Test Session',
            description: 'Testing the Trail Making Test implementation',
            task_sequence: [
              { taskId: 'trail-making-a', order: 1, config: {} },
              { taskId: 'trail-making-b', order: 2, config: {} }
            ],
            current_task_index: 0,
            started_at: null,
            completed_at: null,
            paused_at: null,
            total_duration_seconds: 0,
            active_duration_seconds: 0,
            room_url: null,
            metadata: {},
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString()
          };
        }

        session.set(mockSession);
        tasks.set([]); // Tasks will be loaded when needed
        results.set([]);
        participant.set({
          id: 'p1111111-1111-1111-1111-111111111111',
          external_id: 'TEST001',
          demographics: {
            age: 25,
            gender: 'male',
            education: 'college'
          }
        });
      }

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load session');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function start(): Promise<void> {
    try {
      setLoading(true);
      setError(null);

      const $session = get(session);
      if (!$session) throw new Error('No session loaded');

      if (sessionService) {
        const updated = await sessionService.start($session.id);
        session.set(updated);
      } else {
        updateSession({
          state: 'active',
          started_at: new Date().toISOString()
        });
      }

      activeView.set('execution');

      // Start timer
      stopwatch = createStopwatch((seconds) => {
        elapsedSeconds.set(seconds);
      });
      stopwatch.start();

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to start session');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function pause(): Promise<void> {
    try {
      setLoading(true);
      setError(null);

      updateSession({
        state: 'paused',
        paused_at: new Date().toISOString()
      });

      activeView.set('overview');
      stopwatch?.pause();

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to pause session');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function resume(): Promise<void> {
    try {
      setLoading(true);
      setError(null);

      updateSession({
        state: 'active',
        paused_at: null
      });

      activeView.set('execution');
      stopwatch?.start();

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to resume session');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function complete(): Promise<void> {
    try {
      setLoading(true);
      setError(null);

      const totalDuration = get(results).reduce(
        (sum, r) => sum + (r.duration_seconds || 0), 
        0
      );

      updateSession({
        state: 'completed',
        completed_at: new Date().toISOString(),
        total_duration_seconds: totalDuration
      });

      activeView.set('overview');
      stopwatch?.stop();

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to complete session');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function jumpToTask(index: number): Promise<void> {
    const $tasks = get(tasks);
    const $session = get(session);

    if (!$session || index < 0 || index >= $tasks.length) return;

    try {
      setLoading(true);
      setError(null);

      // If session is draft, start it first
      if ($session.state === 'draft') {
        await start();
      }

      // Mark current task as skipped if in progress
      const currentResults = get(results);
      const currentIndex = get(currentTaskIndex);
      const currentResult = currentResults.find(r => r.task_index === currentIndex);

      if (currentResult?.state === 'in_progress') {
        await skipCurrentTask('Jumped to another task');
      }

      // Update session
      updateSession({
        current_task_index: index
      });

      activeView.set('execution');

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to jump to task');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function skipCurrentTask(reason?: string): Promise<void> {
    const $currentTask = get(currentTask);
    const $currentIndex = get(currentTaskIndex);
    const $tasks = get(tasks);

    if (!$currentTask) return;

    try {
      setLoading(true);
      setError(null);

      // Update current result
      results.update(allResults => {
        const currentResult = allResults.find(r => r.task_index === $currentIndex);
        if (currentResult) {
          currentResult.state = 'skipped';
          currentResult.end_time = new Date().toISOString();
          currentResult.duration_seconds = get(elapsedSeconds);
          currentResult.annotations = {
            ...currentResult.annotations,
            skipped_reason: reason || 'Manual skip'
          };
        }
        return allResults;
      });

      // Move to next task or complete
      const nextIndex = $currentIndex + 1;
      if (nextIndex < $tasks.length) {
        updateSession({ current_task_index: nextIndex });
      } else {
        await complete();
      }

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to skip task');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function submitTaskResult(result: Partial<TaskResult>): Promise<void> {
    const $currentIndex = get(currentTaskIndex);
    const $tasks = get(tasks);

    try {
      setLoading(true);
      setError(null);

      // Update results
      results.update(allResults => {
        const existing = allResults.find(r => r.task_index === $currentIndex);
        if (existing) {
          Object.assign(existing, result);
        }
        return allResults;
      });

      // Auto-advance if configured
      if (config.autoAdvance !== false) {
        const nextIndex = $currentIndex + 1;
        if (nextIndex < $tasks.length) {
          updateSession({ current_task_index: nextIndex });
        } else {
          await complete();
        }
      }

    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to submit result');
      throw err;
    } finally {
      setLoading(false);
    }
  }

  async function updatePresence(data: any): Promise<void> {
    // Implement realtime presence update
    // For now, this is a no-op
  }

  function destroy(): void {
    stopwatch?.destroy();
    // Clean up any subscriptions
  }

  return {
    // State
    session,
    tasks: { subscribe: tasks.subscribe },
    results,
    participant: { subscribe: participant.subscribe },

    // UI State
    currentTaskIndex,
    activeView,
    isLoading: { subscribe: isLoading.subscribe },
    error: { subscribe: error.subscribe },

    // Derived
    currentTask,
    progress,
    canStart,
    canPause,
    canResume,
    isComplete,

    // Actions
    initialize,
    start,
    pause,
    resume,
    complete,
    jumpToTask,
    skipCurrentTask,
    submitTaskResult,
    updatePresence,
    destroy
  };
}

